mapper.sql:
WHERE s.region = #{region}
  AND s.status = 1
  AND s.is_deleted = FALSE

    AND s.category_id = #{categoryId}
    AND EXISTS (
        SELECT 1 FROM category filter_category
        WHERE filter_category.id = s.category_id
          AND filter_category.region = s.region
          AND filter_category.status = 1
    )


    AND s.city_id = #{cityId}
    AND EXISTS (
        SELECT 1 FROM city filter_city
        WHERE filter_city.id = s.city_id
          AND filter_city.region = s.region
          AND filter_city.status = 1
    )


    AND s.area_id = #{areaId}
    AND EXISTS (
        SELECT 1
        FROM area filter_area
        JOIN city filter_area_city
          ON filter_area_city.id = filter_area.city_id
         AND filter_area_city.region = filter_area.region
         AND filter_area_city.status = 1
        WHERE filter_area.id = s.area_id
          AND filter_area.region = s.region
          AND filter_area.status = 1
    )


    AND (
        LOWER(s.name) LIKE CONCAT('%', LOWER(#{keyword}), '%')
        OR LOWER(s.tags) LIKE CONCAT('%', LOWER(#{keyword}), '%')
        OR LOWER(s.address) LIKE CONCAT('%', LOWER(#{keyword}), '%')
    )


    AND s.price_per_capita >= #{minPrice}


    AND s.price_per_capita <= #{maxPrice}


    AND s.score >= #{minScore}


    AND s.has_deal = #{hasDeal}


    AND s.open_now = #{openNow}

WHERE r.region = #{region}
  AND r.shop_id = #{shopId}
  AND r.audit_status = 1
  AND r.status = 1
  AND r.is_deleted = FALSE

    AND r.score_overall >= #{minScore}


    AND EXISTS (SELECT 1 FROM review_image ri WHERE ri.review_id = r.id)


    AND NOT EXISTS (SELECT 1 FROM review_image ri WHERE ri.review_id = r.id)

mapper.update:
UPDATE search_history
SET updated_at = CURRENT_TIMESTAMP
WHERE id = #{id}

mapper.select:
SELECT COUNT(1)
FROM search_history
WHERE user_id = #{userId}
  AND region = #{region}

mapper.delete:
DELETE FROM search_history
WHERE user_id = #{userId}
  AND region = #{region}
